// Check all required environment variables are present and non-empty.
// Fails visibly with a descriptive error if any are absent (SC-16, SC-19).
const required = [
  'DRIVE_FOLDER_ID',
  'CLIENT_EMAIL',
  'REPORT_DAY_TIME',
  'EOD_TIME',
  'DISCORD_BOT_TOKEN',
  'OLLAMA_BASE_URL'
];
const missing = required.filter(k => !process.env[k] || process.env[k].trim() === '');
if (missing.length > 0) {
  throw new Error('FATAL: Missing required environment variables: ' + missing.join(', ') + '. Halting startup. Fix these before running any workflow.');
}
return [{ json: { status: 'env_ok', checked: required } }];

// Load and validate roster.yml (SC-19).
// Throws with a descriptive error if absent or schema is invalid.
const fs = require('fs');
const yaml = require('js-yaml');
const path = process.env.ROSTER_CONFIG_PATH || '/data/roster.yml';
let raw;
try {
  raw = fs.readFileSync(path, 'utf8');
} catch (e) {
  throw new Error('FATAL: roster.yml is absent at ' + path + '. The agent cannot start without a valid roster. (SC-19)');
}
let roster;
try {
  roster = yaml.load(raw);
} catch (e) {
  throw new Error('FATAL: roster.yml is unparseable YAML: ' + e.message + '. Fix the file before starting. (SC-19)');
}
const missingKeys = ['team', 'team_lead', 'client', 'client_channel_id', 'team_lead_channel_id'].filter(k => !roster[k]);
if (missingKeys.length > 0) {
  throw new Error('FATAL: roster.yml is missing required fields: ' + missingKeys.join(', ') + '. (SC-19)');
}
if (!Array.isArray(roster.team) || roster.team.length === 0) {
  throw new Error('FATAL: roster.yml `team` must be a non-empty array. (SC-19)');
}
if (!roster.team_lead.discord_id) {
  throw new Error('FATAL: roster.yml team_lead must have discord_id. (SC-19)');
}
if (!roster.client.discord_id) {
  throw new Error('FATAL: roster.yml client must have discord_id. (SC-19)');
}
return [{ json: { roster, member_count: roster.team.length } }];

// Emit one item per roster member so SplitInBatches can upsert each safely.
// Includes team members and team lead; excludes client (no roster table row needed).
const roster = $input.first().json.roster;
const members = [
  ...roster.team.map(m => ({
    discord_id: m.discord_id,
    name: m.name,
    clockify_id: m.clockify_id || null,
    active: m.active !== false
  })),
  {
    discord_id: roster.team_lead.discord_id,
    name: roster.team_lead.name,
    clockify_id: null,
    active: true
  }
];
return members.map(m => ({ json: m }));

// Read member count and channel ID from upstream nodes
const rosterData = $node['Load Roster YAML'].json;
const roster = rosterData.roster;
const memberCount = rosterData.member_count;
const teamLeadChannelId = roster.team_lead_channel_id;
return [{ json: { team_lead_channel_id: teamLeadChannelId, member_count: memberCount } }];
